  "code": "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Magnetic Dots \u2014 Impacter Pathway</title>\n<style>\n  * { margin: 0; padding: 0; box-sizing: border-box; }\n  body { font-family: 'Helvetica Neue', Arial, sans-serif; background: #06101F; }\n  .section {\n    position: relative; height: 100vh; min-height: 600px;\n    overflow: hidden; display: flex; align-items: center; justify-content: center;\n    text-align: center;\n  }\n  .section canvas { position: absolute; inset: 0; width: 100%; height: 100%; }\n  .content { position: relative; z-index: 5; max-width: 760px; padding: 0 32px; pointer-events: none; }\n  .content a { pointer-events: auto; }\n  .tag {\n    display: inline-block; font-size: 12px; letter-spacing: .14em; text-transform: uppercase;\n    padding: 7px 16px; border-radius: 100px; margin-bottom: 22px; font-weight: 600;\n  }\n  h1 { font-size: clamp(34px, 4.6vw, 58px); font-weight: 600; letter-spacing: -.02em; line-height: 1.12; margin-bottom: 18px; }\n  p { font-size: 17px; line-height: 1.6; max-width: 560px; margin: 0 auto 30px; }\n  .btn { display: inline-block; padding: 13px 28px; border-radius: 100px; font-size: 15px; font-weight: 600; text-decoration: none; }\n  .label {\n    position: absolute; top: 20px; left: 24px; z-index: 6;\n    font-size: 12px; font-weight: 600; letter-spacing: .08em;\n    padding: 6px 14px; border-radius: 6px;\n    background: rgba(0,0,0,.55); color: #fff; backdrop-filter: blur(4px);\n  }\n  /* light sections */\n  .light-s { background: #FBF7F2; }\n  .light-s h1 { color: #0E2A4E; } .light-s p { color: #3B4A61; }\n  .light-s .tag { background: rgba(255,111,97,.12); color: #E85744; border: 1px solid rgba(255,111,97,.35); }\n  .light-s .btn { background: #0E2A4E; color: #FDF9F5; }\n  /* dark sections */\n  .dark-s h1 { color: #FDF9F5; } .dark-s p { color: #DCE6F2; }\n  .dark-s .tag { background: rgba(255,111,97,.16); color: #FFA895; border: 1px solid rgba(255,111,97,.4); }\n  .dark-s .btn { background: #FF6F61; color: #FFF6F1; }\n  #tiles { background: #081A33; }\n  #cubes { background: radial-gradient(ellipse at 50% 115%, #14304F 0%, #0A1F3C 55%, #060F20 100%); }\n</style>\n</head>\n<body>\n\n<section class=\"section light-s\" id=\"dots\">\n  <canvas></canvas>\n  <div class=\"content\">\n    <span class=\"tag\">Impacter Pathway</span>\n    <h1>A field of dots that makes way for you</h1>\n    <p>Navy dots on cream part like a magnetic field around the cursor, blushing coral as they move. Minimal, geometric, alive.</p>\n    <a class=\"btn\" href=\"#\">Get started</a>\n  </div>\n</section>\n\n<script>\n(function () {\n  var lerp = function (a, b, t) { return a + (b - a) * t; };\n  function mix(c1, c2, t) {\n    return [Math.round(lerp(c1[0], c2[0], t)), Math.round(lerp(c1[1], c2[1], t)), Math.round(lerp(c1[2], c2[2], t))];\n  }\n  function rgba(c, a) { return 'rgba(' + c[0] + ',' + c[1] + ',' + c[2] + ',' + a + ')'; }\n  var NAVY = [14, 42, 78], NAVY_L = [74, 120, 184], CORAL = [255, 111, 97], PEACH = [255, 177, 153];\n\n  function setupSection(id, onFrame) {\n    var s = document.getElementById(id);\n    var c = s.querySelector('canvas'), ctx = c.getContext('2d');\n    var state = { mx: -9999, my: -9999, hasMouse: false, t: 0, w: 0, h: 0 };\n    function resize() { c.width = state.w = s.clientWidth; c.height = state.h = s.clientHeight; }\n    resize(); window.addEventListener('resize', resize);\n    s.addEventListener('pointermove', function (e) {\n      var r = s.getBoundingClientRect();\n      state.mx = e.clientX - r.left; state.my = e.clientY - r.top; state.hasMouse = true;\n    });\n    s.addEventListener('pointerleave', function () { state.hasMouse = false; });\n    function frame() {\n      state.t += 0.016;\n      if (!state.hasMouse) { // idle orbit\n        state.mx = state.w * (0.5 + 0.32 * Math.sin(state.t * 0.5));\n        state.my = state.h * (0.5 + 0.25 * Math.cos(state.t * 0.4));\n      }\n      onFrame(ctx, state);\n      requestAnimationFrame(frame);\n    }\n    frame();\n  }\n\n  \n/* ---------- 19 MAGNETIC DOTS ---------- */\n  setupSection('dots', function (ctx, st) {\n    var GAP = 46;\n    ctx.clearRect(0, 0, st.w, st.h);\n    for (var y = GAP / 2; y < st.h + GAP; y += GAP) {\n      for (var x = GAP / 2; x < st.w + GAP; x += GAP) {\n        var dx = x - st.mx, dy = y - st.my;\n        var d = Math.sqrt(dx * dx + dy * dy) || 1;\n        var force = Math.exp(-d / 130) * 46;\n        var px = x + (dx / d) * force;\n        var py = y + (dy / d) * force;\n        var near = Math.max(0, 1 - d / 260);\n        var col = mix(NAVY, CORAL, near);\n        var r = 2.4 + near * 3.4 + Math.sin(st.t + x * 0.02 + y * 0.03) * 0.5;\n        ctx.fillStyle = rgba(col, 0.35 + near * 0.6);\n        ctx.beginPath(); ctx.arc(px, py, Math.max(0.5, r), 0, Math.PI * 2); ctx.fill();\n      }\n    }\n  });\n})();\n</script>\n</body>\n</html>\n"
